class Account:
    def __init__(self, balance):
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
        else:
            print("잔액 부족!")

acc = Account(10000)
acc.deposit(5000)
acc.withdraw(3000)
acc.withdraw(100000)   # 잔액 부족
print("최종 잔액:", acc.balance)

class Stack:
    def __init__(self):
        self.items = []       # 내부 상태(리스트)를 클래스 안에 숨긴다

    def push(self, value):
        self.items.append(value)

    def pop(self):
        if self.items:
            return self.items.pop()
        return None

    def is_empty(self):
        return len(self.items) == 0

s = Stack()
s.push(1)
s.push(2)
s.push(3)
print(s.pop())   # 3 (마지막에 넣은 것이 먼저 나옴)
print(s.pop())   # 2
print(s.is_empty())
